sql:
SELECT artwork_id
FROM artworks
WHERE artist_id = 2;

SELECT s.name, s.email
FROM sellers s
INNER JOIN transactions t ON s.seller_id = t.seller_id
WHERE t.artwork_id = (
    SELECT b.artwork_id
    FROM bids b
    WHERE b.bid_amount = (
        SELECT MAX(bid_amount) FROM bids
    )
);

SELECT COUNT(auction_id) AS total_auctions 
FROM auctions 
WHERE auction_house_id = 3;

SELECT b.name
FROM buyers b
JOIN bids bi ON b.buyer_id = bi.bidder_id
WHERE bi.bid_amount = (
  SELECT MAX(bid_amount) FROM bids
);

SELECT name, location 
FROM auction_houses 
WHERE established_year > 1950;

SELECT auction_id, AVG(hammer_price) AS avg_hammer_price
FROM transactions
GROUP BY auction_id;

SELECT auction_id 
FROM auction_results 
WHERE highest_bid = (SELECT MAX(highest_bid) FROM auction_results);

SELECT * 
FROM auctions 
WHERE minimum_bid > 1000;

SELECT auctions.auction_id, auction_houses.name
FROM auctions
INNER JOIN auction_houses ON auctions.auction_house_id = auction_houses.auction_house_id;

external_knowledge:
- "pulsating heart of this art world" refers to the auction house with the most frequent auction activities;
- "crown jewel in the next month's auctions" refers to the artwork with the latest bid placed within the next 30 days;
- "most voracious collector" refers to the buyer with the highest number of transactions.

sql:
SELECT t.buyer_id, t.seller_id
FROM bids b
JOIN transactions t ON b.bidder_id = t.buyer_id;

external_knowledge:
- "shadowy figures" metaphorically refers to the buyers who participated in auctions;
- "silent whispers" represents the artworks in these auctions;
- "online auction forest" is a metaphor for the virtual space where online auctions occur;
- "failed to reach their destined heights" implies the hammer prices did not meet or exceed the reserve prices;
- "the closest encounters" refers to the transactions that happened between buyers and artworks;
- External knowledge: In the auction context, a hammer price is the final price realized at auction, while a reserve price is the minimum price below which the seller is not willing to sell the item.

sql:
SELECT artist_id, COUNT(*) AS artwork_count
FROM artworks
GROUP BY artist_id;

SELECT bid_amount 
FROM bids 
WHERE bid_amount > (
  SELECT AVG(highest_bid) 
  FROM auction_results
);
